package calculator;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.CsvSource;
import static org.junit.jupiter.api.Assertions.*;

public class CalculatorTest {

    private Calculator calculator;

    @BeforeEach
    void setUp() {
        calculator = new Calculator();
    }

    @Test
    @DisplayName("Addition test with positive numbers")
    void testAddition() {
        assertEquals(5.0, calculator.add(2.0, 3.0), "2.0 + 3.0 should equal 5.0");
    }

    @Test
    @DisplayName("Subtraction test")
    void testSubtraction() {
        assertEquals(2.0, calculator.subtract(5.0, 3.0), "5.0 - 3.0 should equal 2.0");
    }

    @Test
    @DisplayName("Multiplication test")
    void testMultiplication() {
        assertEquals(15.0, calculator.multiply(3.0, 5.0), "3.0 * 5.0 should equal 15.0");
    }

    @Test
    @DisplayName("Division test")
    void testDivision() {
        assertEquals(2.0, calculator.divide(10.0, 5.0), "10.0 / 5.0 should equal 2.0");
    }

    @Test
    @DisplayName("Division by zero should throw ArithmeticException")
    void testDivisionByZero() {
        assertThrows(ArithmeticException.class, () -> calculator.divide(10.0, 0.0),
                "Division by zero should throw ArithmeticException");
    }

    @ParameterizedTest
    @CsvSource({"1.0, 1.0, 2.0", "0.0, 0.0, 0.0", "-1.0, -1.0, -2.0", "-1.0, 1.0, 0.0"})
    @DisplayName("Parameterized addition test")
    void testParameterizedAddition(double a, double b, double expected) {
        assertEquals(expected, calculator.add(a, b), 
                String.format("%f + %f should equal %f", a, b, expected));
    }

    @Test
    @DisplayName("Test with large numbers")
    void testWithLargeNumbers() {
        double a = Double.MAX_VALUE / 2;
        double b = Double.MAX_VALUE / 2;
        assertEquals(a + b, calculator.add(a, b), "Large number addition should work correctly");
    }

    @Test
    @DisplayName("Test with negative numbers")
    void testWithNegativeNumbers() {
        assertEquals(-8.0, calculator.multiply(-2.0, 4.0), "Negative number multiplication should work correctly");
    }
}

#!/usr/bin/env python
# calculator.py

from cement import App, Controller, ex
from cement.core.exc import CaughtSignal
import logging
import os
from datetime import datetime

# Configure logging
LOG_FILE = "calculator_history.log"
logging.basicConfig(
    filename=LOG_FILE,
    level=logging.INFO,
    format='%(asctime)s - %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S'
)

class Calculator(Controller):
    class Meta:
        label = 'calculator'
        help = 'Simple calculator application'
        description = 'A command-line calculator that performs basic arithmetic operations'

    @ex(
        help='addition operation',
        arguments=[
            (['num1'], {'help': 'First number', 'type': float}),
            (['num2'], {'help': 'Second number', 'type': float}),
        ],
    )
    def add(self):
        num1 = self.app.pargs.num1
        num2 = self.app.pargs.num2
        result = num1 + num2

        # Log the operation
        logging.info(f"Addition: {num1} + {num2} = {result}")

        # Output result
        self.app.render({
            'operation': 'Addition',
            'num1': num1,
            'num2': num2,
            'result': result
        })

    @ex(
        help='subtraction operation',
        arguments=[
            (['num1'], {'help': 'First number', 'type': float}),
            (['num2'], {'help': 'Second number', 'type': float}),
        ],
    )
    def subtract(self):
        num1 = self.app.pargs.num1
        num2 = self.app.pargs.num2
        result = num1 - num2

        # Log the operation
        logging.info(f"Subtraction: {num1} - {num2} = {result}")

        # Output result
        self.app.render({
            'operation': 'Subtraction',
            'num1': num1,
            'num2': num2,
            'result': result
        })

    @ex(
        help='multiplication operation',
        arguments=[
            (['num1'], {'help': 'First number', 'type': float}),
            (['num2'], {'help': 'Second number', 'type': float}),
        ],
    )
    def multiply(self):
        num1 = self.app.pargs.num1
        num2 = self.app.pargs.num2
        result = num1 * num2

        # Log the operation
        logging.info(f"Multiplication: {num1} * {num2} = {result}")

        # Output result
        self.app.render({
            'operation': 'Multiplication',
            'num1': num1,
            'num2': num2,
            'result': result
        })

    @ex(
        help='division operation',
        arguments=[
            (['num1'], {'help': 'First number (dividend)', 'type': float}),
            (['num2'], {'help': 'Second number (divisor)', 'type': float}),
        ],
    )
    def divide(self):
        num1 = self.app.pargs.num1
        num2 = self.app.pargs.num2

        # Validate divisor is not zero
        if num2 == 0:
            self.app.log.error("Error: Division by zero is not allowed.")
            return

        result = num1 / num2

        # Log the operation
        logging.info(f"Division: {num1} / {num2} = {result}")

        # Output result
        self.app.render({
            'operation': 'Division',
            'num1': num1,
            'num2': num2,
            'result': result
        })

    @ex(
        help='view operation history',
    )
    def history(self):
        if not os.path.exists(LOG_FILE):
            self.app.log.error("No history found")
            return

        with open(LOG_FILE, 'r') as f:
            history = f.read()

        if not history:
            self.app.log.info("No operations have been recorded yet")
        else:
            self.app.print(history)

class CalculatorApp(App):
    class Meta:
        label = 'calculator'
        handlers = [Calculator]
        # Add a custom output handler to nicely format results
        output_handler = 'jinja2'

        # Add template directory
        template_dir = './templates'

        # Define template for output
        template_module = 'cement.ext.ext_jinja2'

        # Default template for output
        template = 'default.jinja2'

def main():
    with CalculatorApp() as app:
        # Create a templates directory if it doesn't exist
        if not os.path.exists('templates'):
            os.makedirs('templates')

        # Create a default template file
        template_path = os.path.join('templates', 'default.jinja2')
        if not os.path.exists(template_path):
            with open(template_path, 'w') as f:
                f.write("""
{% if operation %}
{{ operation }} Result:
  {{ num1 }} {% if operation == 'Addition' %}+{% elif operation == 'Subtraction' %}-{% elif operation == 'Multiplication' %}*{% elif operation == 'Division' %}/{% endif %} {{ num2 }} = {{ result }}
{% endif %}
                """)

        try:
            app.run()
        except CaughtSignal as e:
            app.log.info(f'Signal caught: {e}')
            app.exit_code = 0

if __name__ == '__main__':
    main()

// app.js
import { watch, h, app, makeEmitter } from 'https://cdn.jsdelivr.net/npm/@whatsup/core@latest/dist/whatsup.min.js';
import { jsx } from 'https://cdn.jsdelivr.net/npm/@whatsup/jsx@latest/dist/whatsup-jsx.min.js';

// Create a reactive state emitter for our items list
const createItemsStore = () => {
  const items = [];
  const emitter = makeEmitter();

  return {
    getItems: () => [...items],
    addItem: (text) => {
      if (text.trim() === '') return false;
      items.push({ id: Date.now(), text });
      emitter.emit();
      return true;
    },
    removeItem: (id) => {
      const index = items.findIndex(item => item.id === id);
      if (index !== -1) {
        items.splice(index, 1);
        emitter.emit();
      }
    },
    subscribe: (callback) => {
      return emitter.subscribe(callback);
    }
  };
};

// Create our store
const itemsStore = createItemsStore();

// Input component with validation
function* Input() {
  let inputValue = '';
  let error = '';

  const updateInput = (e) => {
    inputValue = e.target.value;
    error = '';
    yield;
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!itemsStore.addItem(inputValue)) {
      error = 'Please enter a valid item';
      yield;
      return;
    }

    inputValue = '';
    yield;
  };

  while (true) {
    yield (
      <form className="form-group" onSubmit={handleSubmit}>
        <input 
          type="text" 
          value={inputValue} 
          onInput={updateInput}
          placeholder="Add a new item" 
        />
        <button type="submit">Add</button>
        {error && <div className="error">{error}</div>}
      </form>
    );
  }
}

// Item component
function Item({ id, text }) {
  return (
    <li>
      <span>{text}</span>
      <button 
        className="remove" 
        onClick={() => itemsStore.removeItem(id)}
      >
        Remove
      </button>
    </li>
  );
}

// ItemList component
function* ItemList() {
  let items = itemsStore.getItems();

  // Subscribe to store changes
  const unsubscribe = itemsStore.subscribe(() => {
    items = itemsStore.getItems();
    yield;
  });

  try {
    while (true) {
      yield (
        <ul>
          {items.length === 0 ? 
            <li>No items added yet</li> : 
            items.map(item => <Item key={item.id} id={item.id} text={item.text} />)
          }
        </ul>
      );
    }
  } finally {
    unsubscribe();
  }
}

// App component
function* App() {
  while (true) {
    yield (
      <div className="container">
        <h1>Whatsup Item List</h1>
        <Input />
        <ItemList />
      </div>
    );
  }
}

// Mount our app to the DOM
app(App(), document.getElementById('app'));

