package com.inventory.metrics;

import com.yahoo.elide.annotation.Include;
import com.yahoo.elide.annotation.ReadPermission;
import com.yahoo.elide.core.Path;
import com.yahoo.elide.datastores.aggregation.annotation.CardinalitySize;
import com.yahoo.elide.datastores.aggregation.annotation.ColumnMeta;
import com.yahoo.elide.datastores.aggregation.annotation.DimensionFormula;
import com.yahoo.elide.datastores.aggregation.annotation.Join;
import com.yahoo.elide.datastores.aggregation.annotation.MetricFormula;
import com.yahoo.elide.datastores.aggregation.annotation.TableMeta;
import com.yahoo.elide.datastores.aggregation.metadata.enums.ValueType;
import lombok.Data;
import lombok.EqualsAndHashCode;

import javax.persistence.Id;
import java.math.BigDecimal;

@Include(name = "productMetrics")
@ReadPermission(expression = "allow all")
@TableMeta(
    description = "Product inventory metrics",
    size = CardinalitySize.MEDIUM,
    category = "inventory",
    tags = {"product", "inventory", "metrics"}
)
@Data
@EqualsAndHashCode(of = "id")
@Join(path = "{{products}}", sourceField = "productId", targetField = "id")
public class ProductMetrics {

    @Id
    private String id;

    @DimensionFormula("{{product.id}}")
    @ColumnMeta(description = "Product ID", valueType = ValueType.ID)
    private Long productId;

    @DimensionFormula("{{product.name}}")
    @ColumnMeta(description = "Product Name", valueType = ValueType.TEXT)
    private String productName;

    @MetricFormula("SUM({{product.stockQuantity}})")
    @ColumnMeta(description = "Total Stock Available", valueType = ValueType.NUMBER)
    private Integer totalStock;

    @MetricFormula("SUM({{product.price}} * {{product.stockQuantity}})")
    @ColumnMeta(description = "Total Inventory Value", valueType = ValueType.MONEY)
    private BigDecimal inventoryValue;

    @MetricFormula("COUNT({{product.id}})")
    @ColumnMeta(description = "Total Product Count", valueType = ValueType.NUMBER)
    private Long productCount;

    @MetricFormula("AVG({{product.price}})")
    @ColumnMeta(description = "Average Product Price", valueType = ValueType.MONEY)
    private BigDecimal averagePrice;
}
