package com.inventory.config;

import com.yahoo.elide.Elide;
import com.yahoo.elide.ElideSettingsBuilder;
import com.yahoo.elide.core.audit.AuditLogger;
import com.yahoo.elide.core.audit.Slf4jLogger;
import com.yahoo.elide.core.datastore.DataStore;
import com.yahoo.elide.core.dictionary.EntityDictionary;
import com.yahoo.elide.core.filter.dialect.RSQLFilterDialect;
import com.yahoo.elide.datastores.aggregation.AggregationDataStore;
import com.yahoo.elide.datastores.aggregation.core.Slf4jQueryLogger;
import com.yahoo.elide.datastores.aggregation.queryengines.sql.SQLQueryEngine;
import com.yahoo.elide.datastores.jpa.JpaDataStore;
import com.yahoo.elide.datastores.multiplex.MultiplexManager;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import javax.persistence.EntityManager;
import javax.persistence.EntityManagerFactory;
import java.util.TimeZone;

@Configuration
public class ElideConfig {

    @Bean
    public Elide initializeElide(EntityManagerFactory entityManagerFactory) {
        EntityDictionary dictionary = new EntityDictionary.Builder().build();
        JpaDataStore jpaDataStore = new JpaDataStore(
                () -> entityManagerFactory.createEntityManager(),
                em -> { /* Do nothing */ });

        // Set up aggregation data store
        SQLQueryEngine queryEngine = new SQLQueryEngine(jpaDataStore);
        AggregationDataStore aggregationDataStore = new AggregationDataStore(queryEngine, new Slf4jQueryLogger());

        DataStore multiplexStore = new MultiplexManager(jpaDataStore, aggregationDataStore);

        // Set up audit logging
        AuditLogger auditLogger = new Slf4jLogger();

        // Configure Elide settings
        return new Elide(
                new ElideSettingsBuilder(multiplexStore)
                        .withAuditLogger(auditLogger)
                        .withEntityDictionary(dictionary)
                        .withDefaultMaxPageSize(100)
                        .withDefaultPageSize(50)
                        .withJoinFilterDialect(RSQLFilterDialect.builder().dictionary(dictionary).build())
                        .withSubqueryFilterDialect(RSQLFilterDialect.builder().dictionary(dictionary).build())
                        .build());
    }
}
