package com.inventory.controllers;

import com.yahoo.elide.Elide;
import com.yahoo.elide.ElideResponse;
import com.yahoo.elide.core.request.route.Route;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.servlet.HandlerMapping;

import javax.servlet.http.HttpServletRequest;
import javax.ws.rs.core.MultivaluedHashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/v1")
public class ProductController {

    private final Elide elide;

    @Autowired
    public ProductController(Elide elide) {
        this.elide = elide;
    }

    @GetMapping("/**")
    public ResponseEntity<String> get(HttpServletRequest request,
                                      @RequestParam Map<String, String> allRequestParams) {
        String path = getJsonApiPath(request);

        ElideResponse<String> response = elide.get(
                Route.builder().path(path).parameters(getAllParams(allRequestParams)).build(),
                null,
                "application/json"
        );

        return ResponseEntity.status(response.getStatus()).body(response.getBody());
    }

    @PostMapping("/**")
    public ResponseEntity<String> post(HttpServletRequest request,
                                       @RequestBody String body,
                                       @RequestParam Map<String, String> allRequestParams) {
        String path = getJsonApiPath(request);

        ElideResponse<String> response = elide.post(
                Route.builder().path(path).parameters(getAllParams(allRequestParams)).build(),
                body,
                null,
                "application/json"
        );

        return ResponseEntity.status(response.getStatus()).body(response.getBody());
    }

    @PatchMapping("/**")
    public ResponseEntity<String> patch(HttpServletRequest request,
                                        @RequestBody String body,
                                        @RequestParam Map<String, String> allRequestParams) {
        String path = getJsonApiPath(request);

        ElideResponse<String> response = elide.patch(
                Route.builder().path(path).parameters(getAllParams(allRequestParams)).build(),
                body,
                null,
                "application/json"
        );

        return ResponseEntity.status(response.getStatus()).body(response.getBody());
    }

    @DeleteMapping("/**")
    public ResponseEntity<String> delete(HttpServletRequest request,
                                         @RequestBody(required = false) String body,
                                         @RequestParam Map<String, String> allRequestParams) {
        String path = getJsonApiPath(request);

        ElideResponse<String> response = elide.delete(
                Route.builder().path(path).parameters(getAllParams(allRequestParams)).build(),
                body,
                null,
                "application/json"
        );

        return ResponseEntity.status(response.getStatus()).body(response.getBody());
    }

    private String getJsonApiPath(HttpServletRequest request) {
        String path = (String) request.getAttribute(HandlerMapping.PATH_WITHIN_HANDLER_MAPPING_ATTRIBUTE);
        return path.replaceFirst("/api/v1", "");
    }

    private MultivaluedHashMap<String, String> getAllParams(Map<String, String> params) {
        MultivaluedHashMap<String, String> queryParams = new MultivaluedHashMap<>();
        params.forEach(queryParams::add);
        return queryParams;
    }
}
