package com.inventory.controllers;

import com.yahoo.elide.core.exceptions.HttpStatus;
import com.yahoo.elide.core.exceptions.JsonApiException;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.ControllerAdvice;
import org.springframework.web.bind.annotation.ExceptionHandler;

import javax.validation.ConstraintViolationException;
import java.util.HashMap;
import java.util.Map;
import java.util.stream.Collectors;

@ControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(JsonApiException.class)
    public ResponseEntity<Map<String, Object>> handleJsonApiException(JsonApiException e) {
        Map<String, Object> errorResponse = new HashMap<>();
        errorResponse.put("errors", e.getErrors());
        return ResponseEntity.status(e.getStatus()).body(errorResponse);
    }

    @ExceptionHandler(ConstraintViolationException.class)
    public ResponseEntity<Map<String, Object>> handleConstraintViolation(ConstraintViolationException e) {
        Map<String, Object> errorResponse = new HashMap<>();
        errorResponse.put("errors", e.getConstraintViolations().stream()
                .map(violation -> Map.of(
                        "status", String.valueOf(HttpStatus.SC_BAD_REQUEST),
                        "title", "Validation Error",
                        "detail", violation.getMessage(),
                        "source", Map.of("pointer", "data/attributes/" + violation.getPropertyPath().toString())
                ))
                .collect(Collectors.toList()));

        return ResponseEntity.badRequest().body(errorResponse);
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<Map<String, Object>> handleGenericException(Exception e) {
        Map<String, Object> errorResponse = new HashMap<>();
        errorResponse.put("errors", Map.of(
                "status", String.valueOf(HttpStatus.SC_INTERNAL_SERVER_ERROR),
                "title", "Internal Server Error",
                "detail", e.getMessage()
        ));

        return ResponseEntity.status(HttpStatus.SC_INTERNAL_SERVER_ERROR).body(errorResponse);
