fn handle_window_resize(mut resize_events: EventReader<WindowResized>) {
    for event in resize_events.read() {
        println!(
            "Window resized to: width={}, height={}",
            event.width, event.height
        );
    }
}

fn handle_keyboard_input(
    keyboard_input: Res<Input<KeyCode>>,
    mut query: Query<&mut Sprite, With<Rectangle>>,
) {
    let mut sprite = query.single_mut();

    // Change color based on key press
    if keyboard_input.just_pressed(KeyCode::R) {
        sprite.color = Color::rgb(1.0, 0.0, 0.0); // Red
    } else if keyboard_input.just_pressed(KeyCode::G) {
        sprite.color = Color::rgb(0.0, 1.0, 0.0); // Green
    } else if keyboard_input.just_pressed(KeyCode::B) {
        sprite.color = Color::rgb(0.0, 0.0, 1.0); // Blue
    } else if keyboard_input.just_pressed(KeyCode::Y) {
        sprite.color = Color::rgb(1.0, 1.0, 0.0); // Yellow
    } else if keyboard_input.just_pressed(KeyCode::C) {
        sprite.color = Color::rgb(0.0, 1.0, 1.0); // Cyan
    } else if keyboard_input.just_pressed(KeyCode::M) {
        sprite.color = Color::rgb(1.0, 0.0, 1.0); // Magenta
    } else if keyboard_input.just_pressed(KeyCode::W) {
        sprite.color = Color::rgb(1.0, 1.0, 1.0); // White
    }
}

fn handle_window_close(
    keyboard_input: Res<Input<KeyCode>>,
    mut app_exit_events: EventWriter<AppExit>,
    mut windows: Query<&mut Window, With<PrimaryWindow>>,
) {
    // Handle ESC key to exit application
    if keyboard_input.just_pressed(KeyCode::Escape) {
        app_exit_events.send(AppExit);
    }

    // Check if window close button was pressed
    if let Ok(window) = windows.get_single() {
        if !window.is_focused() {
            println!("Window is not focused");
        }
    }
}

