from cornice import Service
from pyramid.config import Configurator
from pyramid.httpexceptions import HTTPNotFound, HTTPBadRequest
from pyramid.response import Response
import json
import colander

# Book schema for validation
class BookSchema(colander.MappingSchema):
    title = colander.SchemaNode(colander.String(), 
                               validator=colander.Length(min=1, max=100))
    author = colander.SchemaNode(colander.String(), 
                                validator=colander.Length(min=1, max=100))
    isbn = colander.SchemaNode(colander.String(), 
                              validator=colander.Length(min=10, max=13))
    published_year = colander.SchemaNode(colander.Integer(),
                                        validator=colander.Range(min=1000, max=9999))
    genre = colander.SchemaNode(colander.String(), missing='')

# Mock database
BOOKS = {}

# Create book service
books = Service(name='books', path='/books', description="Book management")
book = Service(name='book', path='/books/{isbn}', description="Book detail operations")

# Validator for request data
def validate_book(request, **kwargs):
    try:
        book_data = json.loads(request.body.decode('utf-8')) if request.body else {}
        request.validated = BookSchema().deserialize(book_data)
    except colander.Invalid as e:
        request.errors.add('body', 'book', str(e))
    except json.JSONDecodeError:
        request.errors.add('body', 'book', 'Invalid JSON data')

@books.get()
def get_books(request):
    """Return all books"""
    return {'books': list(BOOKS.values())}

@books.post(validators=validate_book)
def create_book(request):
    """Create a new book"""
    book = request.validated
    isbn = book['isbn']

    if isbn in BOOKS:
        request.errors.add('body', 'isbn', 'Book with this ISBN already exists')
        request.errors.status = 409
        return

    BOOKS[isbn] = book
    return {'status': 'created', 'book': book}

@book.get()
def get_book(request):
    """Get a specific book by ISBN"""
    isbn = request.matchdict['isbn']
    if isbn not in BOOKS:
        raise HTTPNotFound(json_body={'error': f'Book with ISBN {isbn} not found'})

    return {'book': BOOKS[isbn]}

@book.put(validators=validate_book)
def update_book(request):
    """Update a book"""
    isbn = request.matchdict['isbn']
    if isbn not in BOOKS:
        raise HTTPNotFound(json_body={'error': f'Book with ISBN {isbn} not found'})

    book = request.validated
    BOOKS[isbn] = book
    return {'status': 'updated', 'book': book}

@book.delete()
def delete_book(request):
    """Delete a book"""
    isbn = request.matchdict['isbn']
    if isbn not in BOOKS:
        raise HTTPNotFound(json_body={'error': f'Book with ISBN {isbn} not found'})

    del BOOKS[isbn]
    return {'status': 'deleted', 'isbn': isbn}

# Configure and return WSGI app
def main(global_config, **settings):
    config = Configurator(settings=settings)
    config.include('cornice')
    config.scan()
    return config.make_wsgi_app()

if __name__ == '__main__':
    from wsgiref.simple_server import make_server
    app = main({})
    server = make_server('0.0.0.0', 8080, app)
    print("Server started at http://0.0.0.0:8080")
    server.serve_forever()

use cot::{get, post, put, delete, serve, Request, Response, json, State};
use rusqlite::{Connection, Result as SqliteResult};
use serde::{Deserialize, Serialize};
use validator::{Validate, ValidationError};
use std::sync::{Arc, Mutex};
use thiserror::Error;

#[derive(Serialize, Deserialize, Validate, Debug, Clone)]
struct Note {
    id: Option<i64>,
    #[validate(length(min = 1, max = 100, message = "Title must be between 1 and 100 characters"))]
    title: String,
    #[validate(length(min = 1, message = "Content cannot be empty"))]
    content: String,
}

#[derive(Error, Debug)]
enum AppError {
    #[error("Database error: {0}")]
    Database(#[from] rusqlite::Error),
    #[error("Validation error: {0}")]
    Validation(String),
    #[error("Note not found")]
    NotFound,
    #[error("Invalid input: {0}")]
    InvalidInput(String),
    #[error("Mutex lock error")]
    LockError,
}

impl From<AppError> for Response {
    fn from(error: AppError) -> Self {
        match error {
            AppError::Database(e) => Response::internal_server_error().json(json!({
                "error": format!("Database error: {}", e)
            })),
            AppError::Validation(e) => Response::bad_request().json(json!({
                "error": format!("Validation error: {}", e)
            })),
            AppError::NotFound => Response::not_found().json(json!({
                "error": "Note not found"
            })),
            AppError::InvalidInput(e) => Response::bad_request().json(json!({
                "error": format!("Invalid input: {}", e)
            })),
            AppError::LockError => Response::internal_server_error().json(json!({
                "error": "Internal server error"
            })),
        }
    }
}

type AppResult<T> = std::result::Result<T, AppError>;

struct AppState {
    db: Mutex<Connection>,
}

fn init_db(conn: &Connection) -> SqliteResult<()> {
    conn.execute(
        "CREATE TABLE IF NOT EXISTS notes (
            id INTEGER PRIMARY KEY,
            title TEXT NOT NULL,
            content TEXT NOT NULL
        )",
        [],
    )?;
    Ok(())
}

#[get("/notes")]
async fn get_notes(state: State<Arc<AppState>>) -> AppResult<Response> {
    let conn = state.db.lock().map_err(|_| AppError::LockError)?;

    let mut stmt = conn.prepare("SELECT id, title, content FROM notes")?;
    let notes_iter = stmt.query_map([], |row| {
        Ok(Note {
            id: Some(row.get(0)?),
            title: row.get(1)?,
            content: row.get(2)?,
        })
    })?;

    let mut notes = Vec::new();
    for note in notes_iter {
        notes.push(note?);
    }

    Ok(Response::ok().json(json!({ "notes": notes })))
}

#[get("/notes/:id")]
async fn get_note(req: Request, state: State<Arc<AppState>>) -> AppResult<Response> {
    let id: i64 = req.param("id")
        .ok_or_else(|| AppError::InvalidInput("Missing note ID".to_string()))?
        .parse()
        .map_err(|_| AppError::InvalidInput("Invalid note ID".to_string()))?;

    let conn = state.db.lock().map_err(|_| AppError::LockError)?;

    let mut stmt = conn.prepare("SELECT id, title, content FROM notes WHERE id = ?")?;
    let note = stmt.query_row([id], |row| {
        Ok(Note {
            id: Some(row.get(0)?),
            title: row.get(1)?,
            content: row.get(2)?,
        })
    }).map_err(|_| AppError::NotFound)?;

    Ok(Response::ok().json(json!({ "note": note })))
}

#[post("/notes")]
async fn create_note(mut req: Request, state: State<Arc<AppState>>) -> AppResult<Response> {
    let note: Note = req.json().await.map_err(|e| AppError::InvalidInput(e.to_string()))?;

    if let Err(errors) = note.validate() {
        let error_messages: Vec<String> = errors
            .field_errors()
            .values()
            .flat_map(|errs| errs.iter().map(|err| err.message.clone().unwrap_or_default().to_string()))
            .collect();

        return Err(AppError::Validation(error_messages.join(", ")));
    }

    let conn = state.db.lock().map_err(|_| AppError::LockError)?;

    conn.execute(
        "INSERT INTO notes (title, content) VALUES (?, ?)",
        [&note.title, &note.content],
    )?;

    let mut new_note = note.clone();
    new_note.id = Some(conn.last_insert_rowid());

    Ok(Response::created().json(json!({ "note": new_note })))
}

#[put("/notes/:id")]
async fn update_note(mut req: Request, state: State<Arc<AppState>>) -> AppResult<Response> {
    let id: i64 = req.param("id")
        .ok_or_else(|| AppError::InvalidInput("Missing note ID".to_string()))?
        .parse()
        .map_err(|_| AppError::InvalidInput("Invalid note ID".to_string()))?;

    let note: Note = req.json().await.map_err(|e| AppError::InvalidInput(e.to_string()))?;

    if let Err(errors) = note.validate() {
        let error_messages: Vec<String> = errors
            .field_errors()
            .values()
            .flat_map(|errs| errs.iter().map(|err| err.message.clone().unwrap_or_default().to_string()))
            .collect();

        return Err(AppError::Validation(error_messages.join(", ")));
    }

    let conn = state.db.lock().map_err(|_| AppError::LockError)?;

    let rows_affected = conn.execute(
        "UPDATE notes SET title = ?, content = ? WHERE id = ?",
        [&note.title, &note.content, &id.to_string()],
    )?;

    if rows_affected == 0 {
        return Err(AppError::NotFound);
    }

    let mut updated_note = note;
    updated_note.id = Some(id);

    Ok(Response::ok().json(json!({ "note": updated_note })))
}

#[delete("/notes/:id")]
async fn delete_note(req: Request, state: State<Arc<AppState>>) -> AppResult<Response> {
    let id: i64 = req.param("id")
        .ok_or_else(|| AppError::InvalidInput("Missing note ID".to_string()))?
        .parse()
        .map_err(|_| AppError::InvalidInput("Invalid note ID".to_string()))?;

    let conn = state.db.lock().map_err(|_| AppError::LockError)?;

    let rows_affected = conn.execute("DELETE FROM notes WHERE id = ?", [id])?;

    if rows_affected == 0 {
        return Err(AppError::NotFound);
    }

    Ok(Response::ok().json(json!({ "success": true, "message": "Note deleted successfully" })))
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Initialize database connection
    let db_conn = Connection::open("notes.db")?;
    init_db(&db_conn)?;

    let app_state = Arc::new(AppState {
        db: Mutex::new(db_conn),
    });

    println!("Starting server on http://localhost:3000");

    serve()
        .with_state(app_state)
        .add_route(get_notes)
        .add_route(get_note)
        .add_route(create_note)
        .add_route(update_note)
        .add_route(delete_note)
        .run("127.0.0.1:3000")
        .await?;

    Ok(())
}

