import com.yahoo.elide.core.EntityDictionary;
import com.yahoo.elide.core.filter.dialect.RSQLFilterDialect;
import com.yahoo.elide.datastores.jpa.JpaDataStore;
import com.yahoo.elide.datastores.jpa.transaction.NonJtaTransaction;
import org.hibernate.SessionFactory;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import javax.persistence.EntityManagerFactory;
import java.util.HashMap;

@Configuration
public class ElideConfig {

    @Bean
    public Elide initializeElide(EntityManagerFactory entityManagerFactory) {
        EntityDictionary dictionary = new EntityDictionary(new HashMap<>());
        SessionFactory sessionFactory = entityManagerFactory.unwrap(SessionFactory.class);

        JpaDataStore dataStore = new JpaDataStore(
                () -> { return sessionFactory.openSession(); },
                (session) -> { return new NonJtaTransaction(session); }
        );

        return new Elide(new ElideSettingsBuilder(dataStore)
                .withEntityDictionary(dictionary)
                .withJoinFilterDialect(new RSQLFilterDialect(dictionary))
                .withSubqueryFilterDialect(new RSQLFilterDialect(dictionary))
                .build());
    }
}

