package com.example.controller;

import com.yahoo.elide.Elide;
import com.yahoo.elide.ElideResponse;
import com.yahoo.elide.core.exceptions.ForbiddenAccessException;
import com.yahoo.elide.core.exceptions.JsonPatchExtensionException;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.servlet.HandlerMapping;

import javax.servlet.http.HttpServletRequest;
import javax.ws.rs.core.MultivaluedHashMap;
import javax.ws.rs.core.MultivaluedMap;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class ApiController {

    private final Elide elide;

    @Autowired
    public ApiController(Elide elide) {
        this.elide = elide;
    }

    @GetMapping(value = "/**")
    public ResponseEntity<String> get(HttpServletRequest request) {
        String path = getJsonApiPath(request);
        MultivaluedMap<String, String> queryParams = getQueryParams(request);

        ElideResponse response = elide.get(path, queryParams, "");
        return ResponseEntity.status(response.getResponseCode()).body(response.getBody());
    }

    @PostMapping(value = "/**")
    public ResponseEntity<String> post(@RequestBody String body, HttpServletRequest request) {
        String path = getJsonApiPath(request);
        MultivaluedMap<String, String> queryParams = getQueryParams(request);

        ElideResponse response;
        try {
            response = elide.post(path, body, queryParams, "");
        } catch (JsonPatchExtensionException | ForbiddenAccessException e) {
            return ResponseEntity.status(403).body(e.getMessage());
        } catch (Exception e) {
            return ResponseEntity.status(500).body(e.getMessage());
        }
        return ResponseEntity.status(response.getResponseCode()).body(response.getBody());
    }

    @PatchMapping(value = "/**")
    public ResponseEntity<String> patch(@RequestBody String body, HttpServletRequest request) {
        String path = getJsonApiPath(request);
        MultivaluedMap<String, String> queryParams = getQueryParams(request);

        ElideResponse response;
        try {
            response = elide.patch(path, "application/vnd.api+json", body, queryParams, "");
        } catch (JsonPatchExtensionException | ForbiddenAccessException e) {
            return ResponseEntity.status(403).body(e.getMessage());
        } catch (Exception e) {
            return ResponseEntity.status(500).body(e.getMessage());
        }
        return ResponseEntity.status(response.getResponseCode()).body(response.getBody());
    }

    @DeleteMapping(value = "/**")
    public ResponseEntity<String> delete(HttpServletRequest request) {
        String path = getJsonApiPath(request);
        MultivaluedMap<String, String> queryParams = getQueryParams(request);

        ElideResponse response;
        try {
            response = elide.delete(path, "", queryParams, "");
        } catch (JsonPatchExtensionException | ForbiddenAccessException e) {
            return ResponseEntity.status(403).body(e.getMessage());
        } catch (Exception e) {
            return ResponseEntity.status(500).body(e.getMessage());
        }
        return ResponseEntity.status(response.getResponseCode()).body(response.getBody());
    }

    private MultivaluedMap<String, String> getQueryParams(HttpServletRequest request) {
        MultivaluedMap<String, String> queryParams = new MultivaluedHashMap<>();
        for (Map.Entry<String, String[]> entry : request.getParameterMap().entrySet()) {
            for (String value : entry.getValue()) {
                queryParams.add(entry.getKey(), value);
            }
        }
        return queryParams;
    }

    private String getJsonApiPath(HttpServletRequest request) {
        String path = (String) request.getAttribute(HandlerMapping.PATH_WITHIN_HANDLER_MAPPING_ATTRIBUTE);
        return path.replaceFirst("/api", "");
    }
}

