import { h, reactive, mount, effect } from 'whatsup';

// Components
const LoadingSpinner = function*() {
  return <div className="spinner">Loading...</div>;
};

const ErrorMessage = function*({ message }) {
  return <div className="error">{message}</div>;
};

const UserItem = function*({ user }) {
  return (
    <div className="user-item">
      <h3>{user.name}</h3>
      <p>Email: {user.email}</p>
      <p>Phone: {user.phone}</p>
    </div>
  );
};

const UserList = function*({ users }) {
  if (users.length === 0) {
    return <p>No users found</p>;
  }

  return (
    <div className="user-list">
      {users.map(user => <UserItem user={user} key={user.id} />)}
    </div>
  );
};

// Main App
const App = function*() {
  // Reactive state using Whatsup's reactive
  const state = reactive({
    users: [],
    loading: false,
    error: null
  });

  // Fetch users function
  const fetchUsers = async () => {
    state.loading = true;
    state.error = null;

    try {
      const response = await fetch('https://jsonplaceholder.typicode.com/users');

      if (!response.ok) {
        throw new Error(`HTTP error! Status: ${response.status}`);
      }

      const data = await response.json();
      state.users = data;
    } catch (err) {
      state.error = err.message || 'Failed to fetch users';
    } finally {
      state.loading = false;
    }
  };

  // Initial fetch - using Whatsup's effect for side effects
  effect(() => {
    fetchUsers();
  });

  // App UI with reactive rendering
  while (true) {
    yield (
      <div className="app">
        <h1>User Management</h1>
        <button onClick={fetchUsers}>Refresh Users</button>

        {state.loading && <LoadingSpinner />}
        {state.error && <ErrorMessage message={state.error} />}
        {!state.loading && !state.error && <UserList users={state.users} />}
      </div>
    );
  }
};

// Mount the app to the DOM
mount(<App />, document.getElementById('root'));

