#include <iostream>
#include <vector>
#include <string>
#include <map>
#include <functional>
#include <memory> 
#include <stdexcept>
#include <cgraph/cgraph.h>

using namespace CGraph;

class TaskNode : public GNode {
public:
    explicit TaskNode(const std::string& name, std::function<void()> func) 
        : task_name_(name), task_func_(func) {}

    CStatus run() override {
        try {
            std::cout << "Executing task: " << task_name_ << std::endl;
            task_func_();
            std::cout << "Completed task: " << task_name_ << std::endl;
            return CStatus();
        } catch (const std::exception& e) {
            std::cerr << "Error in task " << task_name_ << ": " << e.what() << std::endl;
            return CStatus("Task execution failed");
        }
    }

    const std::string& getTaskName() const {
        return task_name_;
    }

private:
    std::string task_name_;
    std::function<void()> task_func_;
};

class TaskDAG {
public:
    TaskDAG() {
        pipeline_ = GPipelineFactory::create();
    }

    ~TaskDAG() {
        GPipelineFactory::destroy(pipeline_);
    }

    void addTask(const std::string& id, const std::function<void()>& func) {
        if (task_nodes_.find(id) != task_nodes_.end()) {
            throw std::runtime_error("Task ID already exists: " + id);
        }

        auto task_node = std::make_shared<TaskNode>(id, func);
        task_nodes_[id] = task_node;

        pipeline_->registerGElement<TaskNode>(task_node.get());
    }

    void addDependency(const std::string& fromId, const std::string& toId) {
        auto from_it = task_nodes_.find(fromId);
        auto to_it = task_nodes_.find(toId);

        if (from_it == task_nodes_.end()) {
            throw std::runtime_error("Task not found: " + fromId);
        }

        if (to_it == task_nodes_.end()) {
            throw std::runtime_error("Task not found: " + toId);
        }

        try {
            from_it->second->addGDependency(to_it->second.get());
        } catch (const std::exception& e) {
            throw std::runtime_error("Failed to add dependency from " + fromId + " to " + toId + ": " + e.what());
        }
    }

    void execute() {
        try {
            std::cout << "\nExecuting task pipeline:" << std::endl;
            CStatus status = pipeline_->process();

            if (status.isOK()) {
                std::cout << "\nAll tasks completed successfully!" << std::endl;
            } else {
                std::cerr << "\nPipeline execution failed: " << status.getInfo() << std::endl;
            }

            printExecutionResults();
        } catch (const std::exception& e) {
            std::cerr << "Pipeline execution error: " << e.what() << std::endl;
        }
    }

    void printGraph() const {
        std::cout << "\nTask Dependencies:" << std::endl;
        for (const auto& [id, node] : task_nodes_) {
            std::cout << "- Task: " << id << std::endl;
        }
        std::cout << "(Dependencies are managed internally by CGraph)" << std::endl;
    }

private:
    void printExecutionResults() const {
        std::cout << "\nExecution Summary:" << std::endl;
        for (const auto& [id, node] : task_nodes_) {
            std::cout << "- " << id << ": Processed" << std::endl;
        }
    }

    std::map<std::string, std::shared_ptr<TaskNode>> task_nodes_;
    GPipeline* pipeline_;
};

int main() {
    try {
        TaskDAG dag;

        // Define example tasks
        dag.addTask("init", []() { 
            std::cout << "  -> Initializing system resources..." << std::endl; 
        });

        dag.addTask("load_config", []() { 
            std::cout << "  -> Loading configuration files..." << std::endl; 
        });

        dag.addTask("validate_data", []() { 
            std::cout << "  -> Validating input data..." << std::endl; 
        });

        dag.addTask("process_data", []() { 
            std::cout << "  -> Processing data with algorithms..." << std::endl; 
        });

        dag.addTask("generate_report", []() { 
            std::cout << "  -> Generating analysis report..." << std::endl; 
        });

        dag.addTask("cleanup", []() { 
            std::cout << "  -> Cleaning up temporary resources..." << std::endl; 
        });

        // Define task dependencies (from -> to)
        dag.addDependency("init", "load_config");
        dag.addDependency("load_config", "validate_data");
        dag.addDependency("validate_data", "process_data");
        dag.addDependency("process_data", "generate_report");
        dag.addDependency("generate_report", "cleanup");

        // Display the task structure
        dag.printGraph();

        // Execute all tasks in dependency order
        dag.execute();

    } catch (const std::exception& e) {
        std::cerr << "Application error: " << e.what() << std::endl;
        return 1;
    }

    std::cout << "\nApplication finished successfully." << std::endl;
    return 0;
}

