from cement import App, Controller, ex
from cement.core.exc import CaughtArgumentError

class Calculator(Controller):
    class Meta:
        label = 'calculator'
        description = 'A basic calculator CLI'
        arguments = [
            (['-a', '--add'], {'help': 'Addition', 'action': 'store', 'dest': 'add', 'nargs': '+'}),
            (['-s', '--subtract'], {'help': 'Subtraction', 'action': 'store', 'dest': 'subtract', 'nargs': '+'}),
            (['-m', '--multiply'], {'help': 'Multiplication', 'action': 'store', 'dest': 'multiply', 'nargs': '+'}),
            (['-d', '--divide'], {'help': 'Division', 'action': 'store', 'dest': 'divide', 'nargs': '+'}),
        ]

    @ex(help='Perform calculation')
    def calculate(self):
        try:
            if self.app.pargs.add:
                nums = [float(x) for x in self.app.pargs.add]
                result = sum(nums)
                self.app.print(f"Result: {result}")
            elif self.app.pargs.subtract:
                nums = [float(x) for x in self.app.pargs.subtract]
                result = nums[0] - sum(nums[1:])
                self.app.print(f"Result: {result}")
            elif self.app.pargs.multiply:
                nums = [float(x) for x in self.app.pargs.multiply]
                result = 1
                for num in nums:
                    result *= num
                self.app.print(f"Result: {result}")
            elif self.app.pargs.divide:
                nums = [float(x) for x in self.app.pargs.divide]
                if 0 in nums[1:]:
                    self.app.print("Error: Division by zero")
                else:
                    result = nums[0]
                    for num in nums[1:]:
                        result /= num
                    self.app.print(f"Result: {result}")
            else:
                self.app.print("No operation specified. Use -a, -s, -m, or -d")
        except ValueError:
            self.app.print("Error: Invalid number input")

class CalculatorApp(App):
    class Meta:
        label = 'calculator'
        handlers = [Calculator]

def main():
    with CalculatorApp() as app:
        try:
            app.run()
        except CaughtArgumentError as e:
            print(f"Error: {e}")

if __name__ == '__main__':
    main()

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.DisplayName;
import static org.junit.jupiter.api.Assertions.*;

public class CalculatorTest {

    private Calculator calculator;
    private static final double DELTA = 0.0001;

    @BeforeEach
    public void setUp() {
        calculator = new Calculator();
    }

    @Test
    @DisplayName("Test addition with various inputs")
    public void testAddition() {
        assertEquals(5, calculator.add(2, 3), DELTA);
        assertEquals(0, calculator.add(0, 0), DELTA);
        assertEquals(-5, calculator.add(-2, -3), DELTA);
        assertEquals(0, calculator.add(-5, 5), DELTA);
        assertEquals(Double.MAX_VALUE, calculator.add(Double.MAX_VALUE, 0), DELTA);
    }

