# Task data stored in memory
tasks = []
task_id_counter = 1

# Request logging middleware
@app.before_request
def log_request():
    app.logger.info(f"[{time.strftime('%Y-%m-%d %H:%M:%S')}] {request.method} {request.path} - {request.remote_addr}")

# Error handling
@app.errorhandler(400)
def bad_request(error):
    return jsonify({"error": "Bad request", "message": str(error)}), 400

@app.errorhandler(404)
def not_found(error):
    return jsonify({"error": "Not found", "message": "The requested resource was not found"}), 404

@app.errorhandler(500)
def internal_error(error):
    return jsonify({"error": "Internal server error", "message": str(error)}), 500

# Task validation
def validate_task(task_data):
    errors = []

    if not task_data:
        return ["Empty task data"]

    if not isinstance(task_data, dict):
        return ["Task data must be a JSON object"]

    if 'title' not in task_data:
        errors.append("Title is required")
    elif not isinstance(task_data['title'], str) or len(task_data['title']) < 1:
        errors.append("Title must be a non-empty string")

    if 'description' in task_data and not isinstance(task_data['description'], str):
        errors.append("Description must be a string")

    if 'completed' in task_data and not isinstance(task_data['completed'], bool):
        errors.append("Completed must be a boolean")

    return errors

# API routes
@app.route('/api/tasks', methods=['GET'])
def get_tasks():
    return jsonify({"tasks": tasks})

@app.route('/api/tasks/<int:task_id>', methods=['GET'])
def get_task(task_id):
    for task in tasks:
        if task['id'] == task_id:
            return jsonify(task)
    return jsonify({"error": "Task not found"}), 404

@app.route('/api/tasks', methods=['POST'])
def create_task():
    global task_id_counter
    task_data = request.get_json()

    validation_errors = validate_task(task_data)
    if validation_errors:
        return jsonify({"error": "Validation failed", "details": validation_errors}), 400

    new_task = {
        'id': task_id_counter,
        'title': task_data['title'],
        'description': task_data.get('description', ''),
        'completed': task_data.get('completed', False)
    }

    tasks.append(new_task)
    task_id_counter += 1

    return jsonify(new_task), 201

@app.route('/api/tasks/<int:task_id>', methods=['PUT'])
def update_task(task_id):
    task_data = request.get_json()

    validation_errors = validate_task(task_data)
    if validation_errors:
        return jsonify({"error": "Validation failed", "details": validation_errors}), 400

    for task in tasks:
        if task['id'] == task_id:
            task['title'] = task_data['title']
            task['description'] = task_data.get('description', task.get('description', ''))
            task['completed'] = task_data.get('completed', task.get('completed', False))
            return jsonify(task)

    return jsonify({"error": "Task not found"}), 404

@app.route('/api/tasks/<int:task_id>', methods=['DELETE'])
def delete_task(task_id):
    global tasks
    for i, task in enumerate(tasks):
        if task['id'] == task_id:
            del tasks[i]
            return jsonify({"message": f"Task {task_id} deleted successfully"})

    return jsonify({"error": "Task not found"}), 404

