import org.tinylog.Logger;
import org.tinylog.configuration.Configuration;

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

public class UserRegistrationProcessor {
    public static void main(String[] args) {
        // Configure Tinylog with daily rotation
        Configuration.set("writer", "rolling file");
        Configuration.set("writer.file", "logs/registration-{date}.log");
        Configuration.set("writer.pattern", "{date: yyyy-MM-dd HH:mm:ss} [{level}] {class}.{method}: {message}");
        Configuration.set("writer.level", "info");

        String csvFilePath = "users.csv";
        Logger.info("Starting user registration processing from file: {}", csvFilePath);
        processRegistrations(csvFilePath);
        Logger.info("Registration processing completed");
    }

    public static void processRegistrations(String filePath) {
        try (BufferedReader reader = new BufferedReader(new FileReader(filePath))) {
            String line;
            boolean isHeader = true;
            int processedCount = 0;
            int successCount = 0;

            while ((line = reader.readLine()) != null) {
                if (isHeader) {
                    isHeader = false;
                    continue;
                }

                UserRecord user = parseCSVLine(line);
                boolean success = processUserRegistration(user);
                processedCount++;
                if (success) {
                    successCount++;
                }
            }

            Logger.info("Processed {} records, {} successful registrations", processedCount, successCount);
        } catch (IOException e) {
            Logger.error("Failed to read CSV file: {}", e.getMessage());
        }
    }

    private static UserRecord parseCSVLine(String line) {
        String[] fields = line.split(",");
        String name = fields.length > 0 ? fields[0].trim() : "";
        String email = fields.length > 1 ? fields[1].trim() : "";
        String phone = fields.length > 2 ? fields[2].trim() : "";

        return new UserRecord(name, email, phone);
    }

    private static boolean processUserRegistration(UserRecord user) {
        LocalDateTime timestamp = LocalDateTime.now();
        DateTimeFormatter formatter = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss");
        String formattedTimestamp = timestamp.format(formatter);

        if (validateUser(user)) {
            // Registration logic would go here
            Logger.info("User registration successful at {}: {} ({})", 
                    formattedTimestamp, user.getName(), user.getEmail());
            return true;
        } else {
            Logger.warn("User registration failed at {}: Invalid data for user with email {}", 
                    formattedTimestamp, user.getEmail().isEmpty() ? "missing" : user.getEmail());
            return false;
        }
    }

    private static boolean validateUser(UserRecord user) {
        if (user.getName().isEmpty()) {
            Logger.error("Validation failed: Name is required");
            return false;
        }

        if (user.getEmail().isEmpty()) {
            Logger.error("Validation failed: Email is required");
            return false;
        }

        if (!isValidEmail(user.getEmail())) {
            Logger.error("Validation failed: Invalid email format: {}", user.getEmail());
            return false;
        }

        return true;
    }

    private static boolean isValidEmail(String email) {
        // Simple email validation
        return email.matches("^[A-Za-z0-9+_.-]+@(.+)$");
    }

    static class UserRecord {
        private String name;
        private String email;
        private String phone;

        public UserRecord(String name, String email, String phone) {
            this.name = name;
            this.email = email;
            this.phone = phone;
