    StartScreen,
    Playing,
    GameOver,
}

#[derive(Component)]
struct Player {
    speed: f32,
    health: i32,
}

#[derive(Component)]
struct Obstacle;

#[derive(Component)]
struct HealthText;

#[derive(Component)]
struct StartButton;

#[derive(Component)]
struct RestartButton;

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
