                        ..default()
                    },
                    background_color: Color::rgb(0.15, 0.15, 0.15).into(),
                    ..default()
                },
                StartButton,
            ))
            .with_children(|parent| {
                parent.spawn(TextBundle::from_section(
                    "Start Game",
                    TextStyle {
                        font_size: 30.0,
                        color: Color::WHITE,
                        ..default()
                    },
                ));
            });
        });
}

fn player_movement(
    keyboard_input: Res<ButtonInput<KeyCode>>,
    mut query: Query<(&mut Transform, &Player)>,
    time: Res<Time>,
) {
    if let Ok((mut transform, player)) = query.get_single_mut() {
        let mut direction = Vec3::ZERO;

        if keyboard_input.pressed(KeyCode::ArrowUp) {
            direction.y += 1.0;
        }
        if keyboard_input.pressed(KeyCode::ArrowDown) {
            direction.y -= 1.0;
        }
        if keyboard_input.pressed(KeyCode::ArrowRight) {
            direction.x += 1.0;
        }
        if keyboard_input.pressed(KeyCode::ArrowLeft) {
            direction.x -= 1.0;
        }

        if direction != Vec3::ZERO {
            direction = direction.normalize();
        }

        transform.translation += direction * player.speed * time.delta_seconds();

        // Keep player within bounds
        transform.translation.x = transform.translation.x.clamp(-400.0, 400.0);
        transform.translation.y = transform.translation.y.clamp(-300.0, 300.0);
    }
}

fn collision_detection(
    mut player_query: Query<(&Transform, &mut Player)>,
    obstacle_query: Query<&Transform, With<Obstacle>>,
    mut commands: Commands,
    mut next_state: ResMut<NextState<GameState>>,
) {
    if let Ok((player_transform, mut player)) = player_query.get_single_mut() {
        for obstacle_transform in obstacle_query.iter() {
            let distance = player_transform.translation.distance(obstacle_transform.translation);

            if distance < 40.0 {  // Simple collision radius
                player.health -= 1;

                if player.health <= 0 {
                    next_state.set(GameState::GameOver);

                    // Game over UI
                    commands
                        .spawn(NodeBundle {
                            style: Style {
                                width: Val::Percent(100.0),
                                height: Val::Percent(100.0),
                                justify_content: JustifyContent::Center,
                                align_items: AlignItems::Center,
                                flex_direction: FlexDirection::Column,
                                ..default()
                            },
                            ..default()
                        })
                        .with_children(|parent| {
                            parent.spawn(TextBundle::from_section(
                                "Game Over!",
                                TextStyle {
                                    font_size: 50.0,
                                    color: Color::RED,
                                    ..default()
                                },
                            ));

                            parent.spawn((
                                ButtonBundle {
                                    style: Style {
                                        width: Val::Px(200.0),
                                        height: Val::Px(80.0),
                                        justify_content: JustifyContent::Center,
                                        align_items: AlignItems::Center,
                                        margin: UiRect::top(Val::Px(20.0)),
                                        ..default()
                                    },
                                    background_color: Color::rgb(0.15, 0.15, 0.15).into(),
                                    ..default()
                                },
                                RestartButton,
                            ))
                            .with_children(|parent| {
                                parent.spawn(TextBundle::from_section(
                                    "Restart",
                                    TextStyle {
                                        font_size: 30.0,
                                        color: Color::WHITE,
                                        ..default()
                                    },
                                ));
                            });
                        });
                }

                break;
            }
        }
    }
}

fn health_system(
    player_query: Query<&Player>,
    mut text_query: Query<&mut Text, With<HealthText>>,
) {
    if let Ok(player) = player_query.get_single() {
        if let Ok(mut text) = text_query.get_single_mut() {
            text.sections[0].value = format!("Health: {}", player.health);
        }
    }
}

fn button_system(
    mut interaction_query: Query<
        (&Interaction, &mut BackgroundColor, Option<&StartButton>, Option<&RestartButton>),
        (Changed<Interaction>, With<Button>),
    >,
    mut next_state: ResMut<NextState<GameState>>,
    mut commands: Commands,
    game_state: Res<State<GameState>>,
) {
    for (interaction, mut color, start_button, restart_button) in &mut interaction_query {
        match *interaction {
            Interaction::Pressed => {
                *color = Color::rgb(0.35, 0.35, 0.35).into();

                if start_button.is_some() && *game_state.get() == GameState::StartScreen {
                    // Clear UI and start game
                    commands.entity(interaction_query.get_current_entity().unwrap()).despawn_recursive();

                    // Spawn player
                    commands.spawn((
                        SpriteBundle {
                            sprite: Sprite {
                                color: Color::rgb(0.25, 0.25, 0.75),
                                custom_size: Some(Vec2::new(30.0, 30.0)),
                                ..default()
                            },
                            transform: Transform::from_translation(Vec3::new(0.0, 0.0, 0.0)),
                            ..default()
                        },
                        Player {
                            speed: 200.0,
                            health: 3,
                        },
                    ));

                    // Spawn obstacles
                    for i in 0..5 {
                        commands.spawn((
                            SpriteBundle {
                                sprite: Sprite {
                                    color: Color::rgb(0.8, 0.2, 0.2),
                                    custom_size: Some(Vec2::new(50.0, 50.0)),
                                    ..default()
                                },
                                transform: Transform::from_translation(Vec3::new(
                                    100.0 * (i as f32 - 2.0),
                                    200.0,
                                    0.0,
                                )),
                                ..default()
                            },
                            Obstacle,
                        ));
                    }

                    // Health UI
                    commands
                        .spawn(NodeBundle {
                            style: Style {
                                position_type: PositionType::Absolute,
                                top: Val::Px(10.0),
                                left: Val::Px(10.0),
                                ..default()
                            },
                            ..default()
                        })
                        .with_children(|parent| {
                            parent.spawn((
                                TextBundle::from_section(
                                    "Health: 3",
                                    TextStyle {
                                        font_size: 30.0,
                                        color: Color::WHITE,
                                        ..default()
                                    },
                                ),
                                HealthText,
                            ));
                        });

                    next_state.set(GameState::Playing);
                } else if restart_button.is_some() && *game_state.get() == GameState::GameOver {
                    // Restart game
                    commands.entity(interaction_query.get_current_entity().unwrap()).despawn_recursive();
                    next_state.set(GameState::StartScreen);

                    // Clear everything and setup again
                    commands.insert_resource(NextState(Some(GameState::StartScreen)));
                    setup(commands, asset_server.clone());
                }
            }
            Interaction::Hovered => {
                *color = Color::rgb(0.25, 0.25, 0.25).into();
            }
            Interaction::None => {
                *color = Color::rgb(0.15, 0.15, 0.15).into();
            }
        }
    }
}

