#include <iostream>
#include <string>
#include <vector>
#include <chrono>
#include <filesystem>
#include <fstream>
#include <memory>
#include <mutex>
#include <opencv2/opencv.hpp>
#include "CGraph.h"

namespace fs = std::filesystem;

struct ProcessingStats {
    std::string filename;
    double loadTime = 0.0;
    double filterTime = 0.0;
    double saveTime = 0.0;
    bool success = true;
    std::string errorMessage;
};

struct ImageData {
    cv::Mat image;
    ProcessingStats stats;
};

class ImageLoaderNode : public CGraph::GNode {
private:
    std::string inputDir;
    std::vector<std::string> imageFiles;
    std::atomic<size_t> currentIndex{0};

public:
    explicit ImageLoaderNode(const std::string& dir) : inputDir(dir) {
        setName("ImageLoader");

        // Discover image files
        for (const auto& entry : fs::directory_iterator(inputDir)) {
            if (entry.is_regular_file()) {
                std::string ext = entry.path().extension().string();
                std::transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
                if (ext == ".jpg" || ext == ".jpeg" || ext == ".png" || ext == ".bmp") {
                    imageFiles.push_back(entry.path().string());
                }
            }
        }

        std::cout << "Found " << imageFiles.size() << " images to process" << std::endl;
    }

protected:
    CGraph::CStatus run() override {
        size_t index = currentIndex.fetch_add(1);
        if (index >= imageFiles.size()) {
            return CGraph::CStatus::OK;  // No more images to process
        }

        auto start = std::chrono::high_resolution_clock::now();

        auto imageData = std::make_shared<ImageData>();
        imageData->stats.filename = fs::path(imageFiles[index]).filename().string();

        try {
            imageData->image = cv::imread(imageFiles[index]);
            if (imageData->image.empty()) {
                imageData->stats.success = false;
                imageData->stats.errorMessage = "Failed to load image: " + imageFiles[index];
            }
        } catch (const std::exception& e) {
            imageData->stats.success = false;
            imageData->stats.errorMessage = std::string("Exception loading image: ") + e.what();
        }

        auto end = std::chrono::high_resolution_clock::now();
        imageData->stats.loadTime = std::chrono::duration<double>(end - start).count();

        // Pass data to next node
        this->template CGRAPH_SEND_MPARAM(ImageData, imageData);

        return CGraph::CStatus::OK;
    }

    CGraph::CBool isHold() override {
        return currentIndex.load() < imageFiles.size();
    }
};

class ImageFilterNode : public CGraph::GNode {
public:
    ImageFilterNode() {
        setName("ImageFilter");
    }

protected:
    CGraph::CStatus run() override {
        auto imageData = std::make_shared<ImageData>();
        this->template CGRAPH_RECV_MPARAM(ImageData, imageData);

        if (!imageData->stats.success) {
            // Pass through failed images
            this->template CGRAPH_SEND_MPARAM(ImageData, imageData);
            return CGraph::CStatus::OK;
        }

        auto start = std::chrono::high_resolution_clock::now();

        try {
            cv::Mat grayImage;
            cv::cvtColor(imageData->image, grayImage, cv::COLOR_BGR2GRAY);
            imageData->image = grayImage;
        } catch (const std::exception& e) {
            imageData->stats.success = false;
            imageData->stats.errorMessage = std::string("Exception during filtering: ") + e.what();
        }

        auto end = std::chrono::high_resolution_clock::now();
        imageData->stats.filterTime = std::chrono::duration<double>(end - start).count();

        this->template CGRAPH_SEND_MPARAM(ImageData, imageData);

        return CGraph::CStatus::OK;
    }
};

class ImageSaverNode : public CGraph::GNode {
private:
    std::string outputDir;
    std::vector<ProcessingStats> allStats;
    std::mutex statsMutex;

public:
    explicit ImageSaverNode(const std::string& dir) : outputDir(dir) {
        setName("ImageSaver");

        // Create output directory if it doesn't exist
        if (!fs::exists(outputDir)) {
            fs::create_directories(outputDir);
        }
    }

    const std::vector<ProcessingStats>& getStats() const {
        return allStats;
    }

protected:
    CGraph::CStatus run() override {
        auto imageData = std::make_shared<ImageData>();
        this->template CGRAPH_RECV_MPARAM(ImageData, imageData);

        auto start = std::chrono::high_resolution_clock::now();

        if (imageData->stats.success && !imageData->image.empty()) {
            try {
                std::string outputPath = outputDir + "/gray_" + imageData->stats.filename;
                bool saved = cv::imwrite(outputPath, imageData->image);

                if (!saved) {
                    imageData->stats.success = false;
                    imageData->stats.errorMessage = "Failed to save image: " + outputPath;
                }
            } catch (const std::exception& e) {
                imageData->stats.success = false;
                imageData->stats.errorMessage = std::string("Exception saving image: ") + e.what();
            }
        }

        auto end = std::chrono::high_resolution_clock::now();
        imageData->stats.saveTime = std::chrono::duration<double>(end - start).count();

        // Store statistics
        {
            std::lock_guard<std::mutex> lock(statsMutex);
            allStats.push_back(imageData->stats);
        }

        return CGraph::CStatus::OK;
    }
};

void saveStatsToJson(const std::vector<ProcessingStats>& stats, const std::string& outputDir) {
    std::ofstream file(outputDir + "/processing_stats.json");
    if (!file.is_open()) {
        std::cerr << "Failed to create stats file" << std::endl;
        return;
    }

    file << "{\n";
    file << "  \"totalImages\": " << stats.size() << ",\n";
    file << "  \"images\": [\n";

    for (size_t i = 0; i < stats.size(); ++i) {
        const auto& stat = stats[i];
        file << "    {\n";
        file << "      \"filename\": \"" << stat.filename << "\",\n";
        file << "      \"loadTime\": " << stat.loadTime << ",\n";
        file << "      \"filterTime\": " << stat.filterTime << ",\n";
        file << "      \"saveTime\": " << stat.saveTime << ",\n";
        file << "      \"totalTime\": " << (stat.loadTime + stat.filterTime + stat.saveTime) << ",\n";
        file << "      \"success\": " << (stat.success ? "true" : "false");

        if (!stat.success) {
            file << ",\n      \"errorMessage\": \"" << stat.errorMessage << "\"";
        }

        file << "\n    }";
        if (i < stats.size() - 1) {
            file << ",";
        }
        file << "\n";
    }

    file << "  ]\n";
    file << "}\n";

    file.close();
    std::cout << "Processing statistics saved to: " << outputDir << "/processing_stats.json" << std::endl;
}

int main(int argc, char** argv) {
    if (argc < 3) {
        std::cerr << "Usage: " << argv[0] << " <input_directory> <output_directory>" << std::endl;
        return 1;
    }

    std::string inputDir = argv[1];
    std::string outputDir = argv[2];

    // Validate input directory
    if (!fs::exists(inputDir) || !fs::is_directory(inputDir)) {
        std::cerr << "Error: Input directory does not exist or is not a directory: " << inputDir << std::endl;
        return 1;
    }

    try {
        // Create pipeline
        auto loader = std::make_shared<ImageLoaderNode>(inputDir);
        auto filter = std::make_shared<ImageFilterNode>();
        auto saver = std::make_shared<ImageSaverNode>(outputDir);

        // Create pipeline with dependencies
        CGraph::GPipeline pipeline;
        pipeline.setMaxParallelism(4);  // Set concurrency level

        // Add nodes to pipeline with execution order
        pipeline.registerGElement<ImageLoaderNode>(loader);
        pipeline.registerGElement<ImageFilterNode>(filter);
        pipeline.registerGElement<ImageSaverNode>(saver);

        // Set up dependencies: loader -> filter -> saver
        loader->template CGRAPH_LINK_NEXT(filter);
        filter->template CGRAPH_LINK_NEXT(saver);

        std::cout << "Starting image processing pipeline..." << std::endl;
        auto startTime = std::chrono::high_resolution_clock::now();

        // Execute pipeline
        CGraph::CStatus status = pipeline.run();

        auto endTime = std::chrono::high_resolution_clock::now();
        double totalTime = std::chrono::duration<double>(endTime - startTime).count();

        if (status.isOK()) {
            std::cout << "Pipeline completed successfully in " << totalTime << " seconds" << std::endl;

            // Save statistics
            const auto& stats = saver->getStats();
            saveStatsToJson(stats, outputDir);

            // Print summary
            size_t successCount = 0;
            for (const auto& stat : stats) {
                if (stat.success) successCount++;
            }

            std::cout << "Processing Summary:" << std::endl;
            std::cout << "  Total images: " << stats.size() << std::endl;
            std::cout << "  Successful: " << successCount << std::endl;
            std::cout << "  Failed: " << (stats.size() - successCount) << std::endl;
            std::cout << "  Total execution time: " << totalTime << " seconds" << std::endl;

        } else {
            std::cerr << "Pipeline execution failed with status: " << status.getCode() << std::endl;
            return 1;
        }

    } catch (const std::exception& e) {
        std::cerr << "Exception occurred: " << e.what() << std::endl;
        return 1;
    }

    return 0;
}

