// Feed.js
import { render, useState, useEffect } from 'whatsup';
import Post from './Post';
import { connectWebSocket, subscribeToUpdates } from './websocketService';
import { fetchPosts } from './api';
import ErrorBoundary from './ErrorBoundary';
import { useEngagementMetrics } from './hooks/useEngagementMetrics';

// Generator-based component for handling posts
function* postState(initialPosts = []) {
  let currentPosts = [...initialPosts];
  let page = 1;

  while (true) {
    yield currentPosts;

    try {
      const newPosts = yield fetchPosts(page++);
      currentPosts = [...currentPosts, ...newPosts];
    } catch (error) {
      console.error("Failed to fetch more posts:", error);
    }
  }
}

// Custom hook for feed state management
function useFeed() {
  const postsGenerator = useState(function*() {
    const initialPosts = yield fetchPosts(0);
    return yield* postState(initialPosts);
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const loadMorePosts = async function*() {
    setLoading(true);
    try {
      yield postsGenerator.next();
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return { 
    posts: postsGenerator, 
    loading, 
    error, 
    loadMorePosts 
  };
}

// Feed component as a generator function
function* Feed() {
  const { posts, loading, error, loadMorePosts } = useFeed();
  const { trackView, trackEngagement } = useEngagementMetrics();

  // Setup effect for websocket connection
  useEffect(function*() {
    trackView('feed');

    const socket = connectWebSocket();
    const unsubscribe = subscribeToUpdates(socket, (update) => {
      posts.update(currentPosts => {
        return currentPosts.map(post => 
          post.id === update.postId ? { ...post, ...update.data } : post
        );
      });
    });

    return () => unsubscribe();
  });

  // Main render loop
  while (true) {
    const currentPosts = yield* posts;

    if (error && !currentPosts.length) {
      yield <div className="feed-error">Failed to load feed: {error}</div>;
      continue;
    }

    yield (
      <div className="feed-container">
        <h1>Your Feed</h1>
        {currentPosts.map(post => (
          <ErrorBoundary key={post.id} fallback={<div>Error loading post</div>}>
            <Post 
              post={post} 
              onEngagement={(type) => trackEngagement(post.id, type)}
            />
          </ErrorBoundary>
        ))}
        {loading && <div className="loading-indicator">Loading more posts...</div>}
        <button 
          onClick={loadMorePosts} 
          disabled={loading}
          className="load-more-btn"
        >
          Load More
        </button>
      </div>
    );
  }
}

export default Feed;
