// CommentSection.js
import { render, useState } from 'whatsup';
import { addComment, fetchComments } from './api';

function* CommentSection({ postId, comments: initialComments }) {
  // Reactive state for comments
  const [comments, setComments] = useState(initialComments);
  const [newComment, setNewComment] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState(null);

  // Load more comments handler
  const loadMoreComments = function*() {
    try {
      const olderComments = yield fetchComments(postId);
      setComments(current => [...olderComments, ...current]);
    } catch (err) {
      setError("Failed to load more comments");
      console.error(err);
    }
  };

  // Submit comment handler
  const submitComment = function*() {
    const commentText = yield* newComment;
    if (!commentText.trim()) return;

    setIsSubmitting(true);
    setError(null);

    try {
      const commentData = {
        postId,
        content: commentText,
        timestamp: new Date().toISOString()
      };

      // Optimistic update
      const tempId = `temp-${Date.now()}`;
      const tempComment = {
        id: tempId,
        ...commentData,
        author: { name: 'You', avatar: '/assets/default-avatar.png' },
        isPending: true
      };

      setComments(current => [tempComment, ...current]);
      setNewComment('');

      // Actual API call
      const savedComment = yield addComment(commentData);

      // Update with server response
      setComments(current => 
        current.map(c => c.id === tempId ? savedComment : c)
      );
    } catch (err) {
      setError("Failed to post comment");
      console.error(err);

      // Remove failed comment
      setComments(current => 
        current.filter(c => !c.isPending)
      );
    } finally {
      setIsSubmitting(false);
    }
  };

  // Handle input change
  const handleInputChange = (e) => {
    setNewComment(e.target.value);
  };

  // Main render loop
  while (true) {
    const currentComments = yield* comments;
    const currentNewComment = yield* newComment;
    const currentIsSubmitting = yield* isSubmitting;
    const currentError = yield* error;

    yield (
      <div className="comments-section">
        <h4>Comments</h4>

        <div className="comment-form">
          <textarea 
            value={currentNewComment}
            onChange={handleInputChange}
            placeholder="Write a comment..."
            disabled={currentIsSubmitting}
          />
          <button 
            onClick={submitComment}
            disabled={!currentNewComment.trim() || currentIsSubmitting}
          >
            {currentIsSubmitting ? 'Posting...' : 'Post'}
          </button>
        </div>

        {currentError && <div className="comment-error">{currentError}</div>}

        <div className="comments-list">
          {currentComments.length === 0 ? (
            <p className="no-comments">No comments yet. Be the first to comment!</p>
          ) : (
            currentComments.map(comment => (
              <div key={comment.id} className={`comment ${comment.isPending ? 'pending' : ''}`}>
                <img src={comment.author.avatar} alt="Avatar" className="comment-avatar" />
                <div className="comment-content">
                  <div className="comment-header">
                    <span className="comment-author">{comment.author.name}</span>
                    <span className="comment-time">{comment.timestamp}</span>
                  </div>
                  <p>{comment.content}</p>
                </div>
              </div>
            ))
          )}
        </div>

        {currentComments.length > 0 && (
          <button className="load-more-comments" onClick={loadMoreComments}>
            Load older comments
          </button>
        )}
      </div>
    );
  }
}

