// ErrorBoundary.js
import { render, useState } from 'whatsup';

function* ErrorBoundary({ children, fallback }) {
  const [error, setError] = useState(null);

  try {
    while (true) {
      const currentError = yield* error;

      if (currentError) {
        yield typeof fallback === 'function' ? fallback(currentError) : fallback;
      } else {
        try {
          yield children;
        } catch (err) {
          setError(err);
        }
      }
    }
  } catch (err) {
    setError(err);
    return typeof fallback === 'function' ? fallback(err) : fallback;
  }
}

export default ErrorBoundary;
