// hooks/useEngagementMetrics.js
import { useState } from 'whatsup';
import { trackAnalyticsEvent } from '../analyticsService';

export function useEngagementMetrics() {
  const [metrics, setMetrics] = useState({
    viewedPosts: new Set(),
    interactions: []
  });

  // Track page/feed views
  const trackView = (viewType) => {
    trackAnalyticsEvent('view', { type: viewType, timestamp: Date.now() });
  };

  // Track post engagements (likes, comments, shares)
  const trackEngagement = (postId, engagementType) => {
    const event = {
      postId,
      type: engagementType,
      timestamp: Date.now()
    };

    // Track in local state
    setMetrics(current => ({
      ...current,
      interactions: [...current.interactions, event]
    }));

    // Send to analytics service
    trackAnalyticsEvent('engagement', event);

    return event;
  };

  // Track post impressions
  const trackImpression = (postId) => {
    setMetrics(current => {
      // Only track new impressions
      if (current.viewedPosts.has(postId)) {
        return current;
      }

      const newViewedPosts = new Set(current.viewedPosts);
      newViewedPosts.add(postId);

      // Send to analytics
      trackAnalyticsEvent('impression', { postId, timestamp: Date.now() });

      return {
        ...current,
        viewedPosts: newViewedPosts
      };
    });
  };

  return {
    trackView,
    trackEngagement,
    trackImpression,
    getMetrics: () => metrics
  };
}
