// Middleware
async fn rate_limit_middleware(
    req: Request,
    next: middleware::Next,
    rate_limit_storage: RateLimitStorage,
) -> Result<Response, Box<dyn std::error::Error>> {
    let client_ip = req.headers().get("x-forwarded-for")
        .and_then(|h| h.to_str().ok())
        .unwrap_or("127.0.0.1");

    let mut storage = rate_limit_storage.lock().await;
    let current_time = get_current_timestamp();

    let requests = storage.entry(client_ip.to_string()).or_insert_with(Vec::new);

    // Remove old requests outside the window
    requests.retain(|&timestamp| current_time - timestamp < RATE_LIMIT_WINDOW);

    if requests.len() >= RATE_LIMIT_MAX {
        warn!("Rate limit exceeded for IP: {}", client_ip);
        return Ok(Response::builder()
            .status(429)
            .json(&ErrorResponse {
                error: "Too many requests. Please try again later.".to_string(),
            })?);
    }

    requests.push(current_time);

    next.run(req).await
}

async fn auth_middleware(
    req: Request,
    next: middleware::Next,
    required_role: Option<&str>,
) -> Result<Response, Box<dyn std::error::Error>> {
    let auth_header = req.headers().get("authorization")
        .and_then(|h| h.to_str().ok());

    let token = match auth_header {
        Some(header) if header.starts_with("Bearer ") => &header[7..],
        _ => {
            return Ok(Response::builder()
                .status(401)
                .json(&ErrorResponse {
                    error: "Unauthorized".to_string(),
                })?);
        }
    };

    let claims = match verify_jwt_token(token) {
        Ok(claims) => claims,
        Err(_) => {
            return Ok(Response::builder()
