// High score functionality
fn save_high_scores(high_scores: &[HighScore]) {
    if let Ok(file) = File::create("high_scores.json") {
        serde_json::to_writer(file, high_scores).unwrap();
    }
}

fn load_high_scores() -> Vec<HighScore> {
    match File::open("high_scores.json") {
        Ok(file) => {
            let reader = BufReader::new(file);
            match serde_json::from_reader(reader) {
                Ok(scores) => scores,
                Err(_) => Vec::new(),
            }
        }
        Err(_) => Vec::new(),
    }
}

// Difficulty plugin
struct DifficultyPlugin;

impl Plugin for DifficultyPlugin {
    fn build(&self, app: &mut App) {
        app.insert_resource(DifficultySettings {
            enemy_spawn_timer: Timer::new(Duration::from_secs(1), true),
            enemy_speed: 100.0,
            enemy_health: 1,
        });

        app.add_system(update_difficulty);
    }
}

fn update_difficulty(mut settings: ResMut<DifficultySettings>, score: Res<Score>) {
    // Increase difficulty based on score
    let score_val = score.0;

    if score_val > 5000 {
        settings.enemy_spawn_timer = Timer::new(Duration::from_millis(500), true);
        settings.enemy_speed = 200.0;
        settings.enemy_health = 3;
    } else if score_val > 2000 {
        settings.enemy_spawn_timer = Timer::new(Duration::from_millis(700), true);
        settings.enemy_speed = 150.0;
        settings.enemy_health = 2;
    } else if score_val > 1000 {
        settings.enemy_spawn_timer = Timer::new(Duration::from_millis(900), true);
        settings.enemy_speed = 130.0;
        settings.enemy_health = 1;
    }
}

fn main() {
    App::new()
        .insert_resource(WindowDescriptor {
            title: "Space Shooter".to_string(),
            width: 800.0,
            height: 600.0,
            vsync: true,
            resizable: true,
            present_mode: PresentMode::Fifo,
            ..Default::default()
        })
        .insert_resource(Score(0))
        .insert_resource(HighScores(load_high_scores()))
        .add_state(GameState::MainMenu)
        .add_plugins(DefaultPlugins)
        .add_plugin(DifficultyPlugin)
        .add_system(handle_window_resize)
        .add_system_set(
            SystemSet::on_enter(GameState::MainMenu)
                .with_system(setup_menu)
        )
        .add_system_set(
            SystemSet::on_update(GameState::MainMenu)
                .with_system(menu_interaction)
        )
        .add_system_set(
            SystemSet::on_enter(GameState::Playing)
                .with_system(setup_ui)
                .with_system(spawn_player)
        )
        .add_system_set(
            SystemSet::on_update(GameState::Playing)
                .with_system(player_movement)
                .with_system(player_shooting)
                .with_system(player_damage_animation)
                .with_system(projectile_movement)
                .with_system(spawn_enemies)
                .with_system(enemy_movement)
                .with_system(collision_detection)
                .with_system(update_particles)
                .with_system(update_ui)
        )
        .add_system_set(
            SystemSet::on_enter(GameState::GameOver)
                .with_system(setup_game_over)
        )
        .add_system_set(
            SystemSet::on_update(GameState::GameOver)
                .with_system(game_over_interaction)
        )
        .run();
}

