bool SensorValidator::validateChecksum(const SensorData& data) {
    uint32_t calculatedChecksum = calculateChecksum(data.rawData, data.rawDataSize);
    return calculatedChecksum == data.checksum;
}

bool SensorValidator::validate(const SensorData& data) {
    try {
        return validateRange(data) && 
               validateFormat(data) && 
               validateChecksum(data);
    } catch (...) {
        return false;
    }
}

bool SensorValidator::isInValidRange(SensorType type, double value) {
    switch (type) {
        case SensorType::TEMPERATURE:
            return value >= -50.0 && value <= 150.0;
        case SensorType::PRESSURE:
            return value >= 0.0 && value <= 1000.0;
        case SensorType::HUMIDITY:
            return value >= 0.0 && value <= 100.0;
        case SensorType::ACCELERATION:
            return value >= -20.0 && value <= 20.0;
        default:
            return false;
    }
}

bool SensorValidator::isValidFormat(const std::string& format, SensorType type) {
    if (format.empty()) return false;

    switch (type) {
        case SensorType::TEMPERATURE:
            return format == "C" || format == "F" || format == "K";
        case SensorType::PRESSURE:
            return format == "Pa" || format == "kPa" || format == "bar";
        case SensorType::HUMIDITY:
            return format == "%" || format == "RH";
        case SensorType::ACCELERATION:
            return format == "m/s^2" || format == "g";
        default:
            return false;
    }
}

uint32_t SensorValidator::calculateChecksum(const void* data, size_t size) {
    if (!data || size == 0) return 0;

    uint32_t checksum = 0;
    const uint8_t* bytes = static_cast<const uint8_t*>(data);
    for (size_t i = 0; i < size; i++) {
        checksum = (checksum << 1) ^ bytes[i];
    }
    return checksum;
}

