# Makefile for Sensor Validator with CppUTest

# Compiler and flags
CXX = g++
CXXFLAGS = -Wall -Wextra -g -std=c++11

# CppUTest paths - update these according to your installation
CPPUTEST_HOME ?= /usr/local
CPPUTEST_INCLUDE = -I$(CPPUTEST_HOME)/include
CPPUTEST_LIBS = -L$(CPPUTEST_HOME)/lib -lCppUTest -lCppUTestExt

# Include paths
INCLUDES = $(CPPUTEST_INCLUDE)

# Source files
SRC = sensor_validator.cpp sensor_tests.cpp

# Object files
OBJ = $(SRC:.cpp=.o)

# Target executable
TARGET = sensor_test_runner

# Build rules
all: $(TARGET)

$(TARGET): $(OBJ)
	$(CXX) $(CXXFLAGS) -o $@ $^ $(CPPUTEST_LIBS)

%.o: %.cpp
	$(CXX) $(CXXFLAGS) $(INCLUDES) -c $< -o $@

# Run tests
test: $(TARGET)
	./$(TARGET) -v

# Clean
clean:
	rm -f $(OBJ) $(TARGET) sensor_validator_tests.xml

# Memory leak test run
memcheck: $(TARGET)
	./$(TARGET) -v -m

.PHONY: all test clean memcheck
