      <input v-model="newTask.title" placeholder="Task title" />
      <select v-model="newTask.status">
        <option value="To Do">To Do</option>
        <option value="In Progress">In Progress</option>
        <option value="Done">Done</option>
      </select>
      <button @click="addTask">Add Task</button>
    </div>

    <div class="filters">
      <button @click="currentFilter = 'All'" :class="{ active: currentFilter === 'All' }">All</button>
      <button @click="currentFilter = 'To Do'" :class="{ active: currentFilter === 'To Do' }">To Do</button>
      <button @click="currentFilter = 'In Progress'" :class="{ active: currentFilter === 'In Progress' }">In Progress</button>
      <button @click="currentFilter = 'Done'" :class="{ active: currentFilter === 'Done' }">Done</button>
    </div>

    <div class="tasks">
      <task-item
        v-for="task in filteredTasks"
        :key="task.id"
        :task="task"
        @edit="editTask"
        @delete="deleteTask"
        @status-change="changeTaskStatus"
      ></task-item>
    </div>
  </div>
</template>

<script>
import TaskItem from './components/TaskItem.vue';

export default {
  components: {
    TaskItem
  },
  data() {
    return {
      tasks: [],
      newTask: {
        title: '',
        status: 'To Do'
      },
      currentFilter: 'All',
      nextId: 1
    };
  },
  computed: {
    filteredTasks() {
      if (this.currentFilter === 'All') {
        return this.tasks;
      }
      return this.tasks.filter(task => task.status === this.currentFilter);
    }
  },
  methods: {
    addTask() {
      if (!this.newTask.title) return;

      this.tasks.push({
        id: this.nextId++,
        title: this.newTask.title,
        status: this.newTask.status
      });

      this.newTask.title = '';
      this.newTask.status = 'To Do';
    },
    editTask(updatedTask) {
      const index = this.tasks.findIndex(task => task.id === updatedTask.id);
      if (index !== -1) {
        this.tasks[index] = { ...updatedTask };
      }
    },
    deleteTask(taskId) {
      this.tasks = this.tasks.filter(task => task.id !== taskId);
    },
    changeTaskStatus(taskId, newStatus) {
      const task = this.tasks.find(task => task.id === taskId);
      if (task) {
        task.status = newStatus;
      }
    }
  }
};
</script>

